SELECT ?country WHERE {
  ?event rdfs:label "2017 Men's Pan American Fencing Championship" @en ; wdt:P31 wd:Q2772679 ; wdt:P1264 ?start ; wdt:P1265 ?end .
  FILTER(?start <= "2017-06-18" ^^ xsd:date && ?end >= "2017-06-13" ^^ xsd:date)
  .
  ?country wdt:P1089 ?event ; wdt:P1346 "4th" ; wdt:P36 wd:Q1168 .
}

SELECT ?player ?nickname WHERE {
  ?series rdfs:label "The Match" @en ; wdt:P31 wd:Q7325 .
  ?series wdt:P161 ?player .
  ?player wdt:P2056 ?pos1 .
  ?player wdt:P2056 ?pos2 .
  FILTER(?pos1 != ?pos2)
  OPTIONAL {
    ?player wdt:P1448 ?nickname
  }
}

